UPDATE DW.NotePeriodicCalcBI SET DW.NotePeriodicCalcBI.Accountid = a.accountid
,DW.NotePeriodicCalcBI.AccountTypeID = a.AccountTypeID
,DW.NotePeriodicCalcBI.AccountTypeBI = a.AccountTypeBI
From(
    Select noteid,acc.accountid,acc.AccountTypeID, ac.name as AccountTypeBI
	from cre.note n
    inner join core.account acc on acc.accountid = n.account_accountid
	left join core.accountcategory ac on ac.accountcategoryid = acc.AccountTypeID
    where acc.isdeleted <> 1
)a
